"use strict";(globalThis.webpackChunkmythogen_engine_blog=globalThis.webpackChunkmythogen_engine_blog||[]).push([[8940],{1238(e,t,n){n.r(t),n.d(t,{assets:()=>h,contentTitle:()=>r,default:()=>c,frontMatter:()=>a,metadata:()=>o,toc:()=>l});var s=n(4848),i=n(8453);const a={},r="Final Chapter: Games Are the Future (v5b)",o={id:"GameVictory/\u7d42\u7ae0_\u904a\u6232\u5373\u672a\u4f86_v5b",title:"Final Chapter: Games Are the Future (v5b)",description:"Two in the morning.",source:"@site/i18n/en/docusaurus-plugin-content-docs/current/GameVictory/\u7d42\u7ae0_\u904a\u6232\u5373\u672a\u4f86_v5b.md",sourceDirName:"GameVictory",slug:"/GameVictory/\u7d42\u7ae0_\u904a\u6232\u5373\u672a\u4f86_v5b",permalink:"/MythogenEngine/en/docs/GameVictory/\u7d42\u7ae0_\u904a\u6232\u5373\u672a\u4f86_v5b",draft:!1,unlisted:!1,tags:[],version:"current",frontMatter:{},sidebar:"docs",previous:{title:"Chapter Eleven: A Love Letter to Gamers \u2014 Sega's Sacrifice and Nintendo's Walled Garden",permalink:"/MythogenEngine/en/docs/GameVictory/\u7b2c\u5341\u4e00\u7ae0_\u7d66\u904a\u6232\u73a9\u5bb6\u7684\u60c5\u66f8_v4"},next:{title:"Side Story (Upper): The Prison Breaker \u2014 Google's Soulless Gamble and the TPU Closed Loop",permalink:"/MythogenEngine/en/docs/GameVictory/\u5916\u50b3\u4e0a\u7bc7_\u9003\u7344\u8005_Google\u7684\u7121\u9b42\u8c6a\u8ced\u8207TPU\u9589\u74b0_v1"}},h={},l=[{value:"I. Convergence",id:"i-convergence",level:2},{value:"II. Three Interrogations",id:"ii-three-interrogations",level:2},{value:"III. The Death of Systems Thinking",id:"iii-the-death-of-systems-thinking",level:2},{value:"IV. The Final Arithmetic",id:"iv-the-final-arithmetic",level:2}];function d(e){const t={code:"code",h1:"h1",h2:"h2",header:"header",hr:"hr",img:"img",p:"p",strong:"strong",...(0,i.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(t.header,{children:(0,s.jsx)(t.h1,{id:"final-chapter-games-are-the-future-v5b",children:"Final Chapter: Games Are the Future (v5b)"})}),"\n",(0,s.jsx)(t.p,{children:"Two in the morning."}),"\n",(0,s.jsx)(t.p,{children:"The same moment that opened the prologue. The Steam Deck beside me is running a Windows game \u2014 Proton's translation layer on Linux, converting every DirectX call into Vulkan. Chapter Six's story. The iPhone notification flashes and fades \u2014 its chip from TSMC's 3nm line. Chapter Eight's story. Somewhere beyond the window, in a data center, thousands of NVIDIA H100 cards are computing the next set of weights for a large language model \u2014 every CUDA core inside those cards was funded by eighteen years of R&D tax paid by gamers. Chapter Seven's story."}),"\n",(0,s.jsx)(t.p,{children:"But this time, there's something new."}),"\n",(0,s.jsx)(t.p,{children:"Under the TV stand sits a Nintendo Switch 2. $450. NVIDIA Ampere architecture. Tensor cores. DLSS. The AI upscaling algorithm running inside this console and the Tensor cores inside the H100 share the same design lineage."}),"\n",(0,s.jsx)(t.p,{children:"Everything in this room has a causal chain leading back to a chapter in this book. And every causal chain ultimately converges on the same starting point."}),"\n",(0,s.jsx)(t.p,{children:"Someone wanted to play a better game."}),"\n",(0,s.jsx)(t.hr,{}),"\n",(0,s.jsx)(t.h2,{id:"i-convergence",children:"I. Convergence"}),"\n",(0,s.jsx)(t.p,{children:"Looking back from 2026, the last forty years of technology history reveal an awe-inspiring convergence."}),"\n",(0,s.jsx)(t.p,{children:"In 1993, a young man decided in a Denny's restaurant to build a graphics card that would make PC games look better. In 2026, his company is worth over $5 trillion, and every company in the world that wants to do AI is lining up to buy his chips."}),"\n",(0,s.jsx)(t.p,{children:"In 1995, a Microsoft engineer was dispatched to convince John Carmack to accept Windows. Thirty years later, Microsoft spends over $100 billion a year building AI data centers \u2014 and the operating system running in those data centers is Linux, the system Carmack trusted most."}),"\n",(0,s.jsx)(t.p,{children:"In 1996, a Japanese executive handed $5 million to a young man who had made a fatal mistake. In 2026, that $5 million has grown into the deepest technology monopoly in human history."}),"\n",(0,s.jsx)(t.p,{children:"In 1998, TSMC signed its first strategic partnership agreement with NVIDIA. In 2026, every one of the world's most advanced AI chips \u2014 H100, B200 \u2014 comes off TSMC's production lines in Hsinchu. The yield rates on those lines were forged by large-die orders for gaming GPUs."}),"\n",(0,s.jsx)(t.p,{children:"In 2006, Jensen Huang quietly embedded general-purpose compute cores inside every GeForce 8800 GTX. In 2012, a Ukrainian-born doctoral student used two gaming graphics cards in his parents' bedroom to ignite the deep learning revolution. In 2022, ChatGPT launched. At every node of this causal chain stands a gamer's dollar bill."}),"\n",(0,s.jsx)(t.p,{children:"Software, compute, silicon. DirectX, CUDA, TSMC. Three seemingly parallel technology trees, all merging at the summit of the AI era."}),"\n",(0,s.jsx)(t.p,{children:"But the cost of that merger has been surfacing, link by link, across the final three chapters of this book."}),"\n",(0,s.jsx)(t.hr,{}),"\n",(0,s.jsx)(t.h2,{id:"ii-three-interrogations",children:"II. Three Interrogations"}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"First question: Why does every turning point in tech hegemony begin with games?"})}),"\n",(0,s.jsxs)(t.p,{children:["This book spent eleven chapters answering that question, but it can be compressed into a single sentence: ",(0,s.jsx)(t.strong,{children:"Because gamers are the only consumer group in human history willing to spend thousands of dollars every two years just to make the reflections on a virtual water surface look slightly more realistic."})]}),"\n",(0,s.jsx)(t.p,{children:"No other industry has consumers like this. Enterprise users buy servers to save money \u2014 they calculate every cent. Research institutions buy supercomputers with government grants \u2014 long cycles, fixed budgets. Only gamers pay out of their own pockets, willingly, and with appetites that never plateau."}),"\n",(0,s.jsx)(t.p,{children:"These people constitute a perfect pressure-testing ground plus R&D funding pool. Their money fed NVIDIA's CUDA for a decade (Chapter Seven). Their GPU orders forced TSMC to push large-die yields to the limit (Chapter Eight). Their obsession with visual fidelity compelled each generation of GPU to breach the silicon limits of the previous one \u2014 and those breached limits happened to be precisely the limits that AI computation needed."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Games are not a byproduct of technological revolution. Games are the pressure-testing ground and the cash register of technological revolution."})}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Second question: In this forty-year fight, why did some companies survive while others fell?"})}),"\n",(0,s.jsx)(t.p,{children:"The answer is not a matter of genius. Every protagonist in this book \u2014 Jensen Huang, Bill Gates, Lisa Su, Pat Gelsinger, Gabe Newell, Morris Chang \u2014 is among the most brilliant minds in their respective fields. Genius was not in short supply."}),"\n",(0,s.jsx)(t.p,{children:"The difference is institutional structure."}),"\n",(0,s.jsx)(t.p,{children:"Chapter Nine's conclusion: Intel's MDF and its vertically integrated service apparatus produced an empire that couldn't move. Gelsinger saw all the problems, but the entrenched interest structures were too deep, and Wall Street wouldn't give him time. Lisa Su won \u2014 not because she was smarter, but because AMD had been beaten to the bottom. The bottom meant freedom. Freedom meant being able to place all resources on a single bet."}),"\n",(0,s.jsx)(t.p,{children:"Chapter Ten's conclusion: Nadella has real authority, and his direction may be correct \u2014 but the thing he's dismantling (gaming's function as a pressure-testing ground) won't send its bill for another decade. Ryan had real authority, and his direction has already been proven wrong \u2014 the corpses of live-service games are piling up."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"The succession of tech hegemony is not an intelligence contest between geniuses. It is Darwinian evolution among organizational structures, entangled interests, and time horizons."})}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Third question: When giants dismantle their own pressure-testing grounds with their own hands, is this transformation or suicide?"})}),"\n",(0,s.jsx)(t.p,{children:"This is the book's final question, and the only one that still has no answer."}),"\n",(0,s.jsx)(t.p,{children:"Microsoft's AI capital expenditure in 2026 exceeds $100 billion. It shut down Tango Gameworks, Arkane Austin, The Initiative. It let Turn 10 \u2014 the team behind the ForzaTech engine \u2014 lay off nearly half its staff. It used the savings to buy NVIDIA GPUs for AI data centers."}),"\n",(0,s.jsx)(t.p,{children:"Sony spent $200 million making a game that lasted fourteen days. Shut down Japan Studio. Shut down Bluepoint. Shut down Firewalk. Jim Ryan retired with enough wealth for several lifetimes."}),"\n",(0,s.jsxs)(t.p,{children:["Two companies, two different methods, the same action: ",(0,s.jsx)(t.strong,{children:"treating games as means rather than ends, treating players as chips rather than customers."})]}),"\n",(0,s.jsx)(t.p,{children:"Chapter Three wrote that sentence. Back then it was a forecast. Chapter Ten turned it into a settlement."}),"\n",(0,s.jsxs)(t.p,{children:["But on that settlement's bill, there is one line no one has been able to calculate yet: ",(0,s.jsx)(t.strong,{children:'When the world\'s two largest gaming platform holders simultaneously decide that "games are not a core business," the pressure-testing grounds, R&D funding pools, and long-term chip orders they simultaneously tear down \u2014 how large a gap will these leave in the semiconductor supply chain over the next decade?'})]}),"\n",(0,s.jsx)(t.p,{children:"No CEO asks this question. Because the causal chain is too long \u2014 too many layers between Xbox layoffs and TSMC capacity planning. And Wall Street only looks at the next quarter."}),"\n",(0,s.jsx)(t.hr,{}),"\n",(0,s.jsx)(t.h2,{id:"iii-the-death-of-systems-thinking",children:"III. The Death of Systems Thinking"}),"\n",(0,s.jsxs)(t.p,{children:["This book's preface told a personal story. A teenager growing up in Mong Kok's Sino Centre in 1990s Hong Kong, who learned the entire architecture of a CPU by accident \u2014 through editing ",(0,s.jsx)(t.code,{children:"config.sys"}),", memorizing IRQ interrupt numbers, pressing 255 into ",(0,s.jsx)(t.code,{children:"FF"})," on a Casio calculator."]}),"\n",(0,s.jsx)(t.p,{children:"That learning path \u2014 starting from games, penetrating the operating system, reaching all the way to bare hardware \u2014 has almost completely disappeared today."}),"\n",(0,s.jsxs)(t.p,{children:["A young engineer in 2026 doesn't need to know what an IRQ is. Doesn't need to know how to configure VGA registers. Doesn't need to know how memory pages are partitioned. They open PyTorch, call ",(0,s.jsx)(t.code,{children:"model.train()"}),", and everything underneath \u2014 cuDNN, cuBLAS, PTX, SASS, every transistor switch on the GPU \u2014 is encapsulated as a black box."]}),"\n",(0,s.jsx)(t.p,{children:"This isn't a bad thing. Abstraction layers are the only way to manage complexity. The preface already said it: the problem isn't abstraction layers themselves \u2014 the problem is when abstraction layers become black boxes."}),"\n",(0,s.jsx)(t.p,{children:"Black boxes mean: you can use it, but you can't open it. You can optimize on its surface, but you can't penetrate it to redesign the foundation."}),"\n",(0,s.jsx)(t.p,{children:"John Carmack is Carmack because he grew up in an era when hardware was naked. He had to write directly to VGA memory, had to understand how every CPU clock cycle was spent. Jensen Huang could see the seam inside the GPU \u2014 from graphics rendering to general-purpose compute \u2014 because he straddled hardware design and business strategy, seeing through the entire stack. Lisa Su could rescue AMD from rock bottom because her technical foundation ran from semiconductor physics to system architecture, touching every layer."}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"These people share one trait: they could see through the entire system \u2014 from transistor to API to application layer."}),' The preface called this ability "systems thinking."']}),"\n",(0,s.jsx)(t.p,{children:"But in the fast-food AI era of 2026, the brightest minds are all learning how to call pre-built tools \u2014 how to chain LangChain, how to fine-tune LoRA, how to use Agents for workflow automation. These skills have value. But they all stand on the surface of the black box."}),"\n",(0,s.jsx)(t.p,{children:"And what's more unsettling is that this problem isn't just about students \u2014 it's embedded in the very structure of education."}),"\n",(0,s.jsx)(t.p,{children:'The way industry demands engineers has changed fundamentally. The proliferation of AI-assisted development tools is compressing software teams to single-digit headcounts. Hiring standards no longer allow "bring them in and train them slowly" \u2014 companies want engineers who are battle-ready from day one. But the curriculum still teaches routes from five years ago. The students aren\'t lacking in intelligence. No one has told them the road has changed.'}),"\n",(0,s.jsx)(t.p,{children:"Here lies an irony."}),"\n",(0,s.jsx)(t.p,{children:"The things that schools don't teach \u2014 game engine internals, real-time rendering pipeline design, how to schedule parallel computation on a GPU \u2014 happen to be precisely the bridge to the most advanced frontiers of the AI era. NVIDIA's Isaac Sim \u2014 the core simulation platform for physical AI \u2014 is built on Omniverse and the PhysX physics engine. PhysX is also the default physics engine in Unreal Engine; Omniverse's scene description format, OpenUSD, is also the data interchange standard for Houdini and Hollywood's visual effects industry. These systems differ in architecture and purpose \u2014 game engines pursue real-time interactive performance, Houdini pursues procedural content generation, Isaac Sim pursues high-fidelity robotic training simulation \u2014 but the core skills they require overlap heavily: understanding how GPUs schedule parallel computation, understanding how scene graphs organize 3D data, understanding how physics engines solve collisions and mechanics in every frame. An engineer who has ground through the internals of a game engine faces a far lower barrier to pivoting toward physical AI than someone who can only call APIs."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"But no one tells them this. Because the curriculum has no path for it. Students walk the same old road their predecessors walked. At the end of that old road sits a position that AI is already downsizing away. And beside it, the trail that leads to the new world \u2014 the trail from game-engine internals through to AI infrastructure \u2014 is overgrown with weeds, because no curriculum guides them through it."})}),"\n",(0,s.jsx)(t.p,{children:"The soil for cultivating engineers with systems thinking is collapsing from both ends simultaneously. One end is industry \u2014 pressure-testing grounds being dismantled, studios being shut, games being treated as numbers on a spreadsheet. The other end is education \u2014 curricula that can't keep up, students who don't know the road has changed, the most valuable cross-layer learning paths left untaught."}),"\n",(0,s.jsx)(t.p,{children:'If we stop cultivating the kind of engineer who is willing to dive deep into the machine \u2014 the kind who asks "what\'s underneath this API," "why was this chip designed this way," "what cost is hidden behind this abstraction layer" \u2014'}),"\n",(0,s.jsx)(t.p,{children:"Then, when the next great wave of technological revolution arrives, who will write the first line of code that breaks through?"}),"\n",(0,s.jsx)(t.hr,{}),"\n",(0,s.jsx)(t.h2,{id:"iv-the-final-arithmetic",children:"IV. The Final Arithmetic"}),"\n",(0,s.jsx)(t.p,{children:"This book has recorded eight variations of the pattern."}),"\n",(0,s.jsx)(t.p,{children:"Chapter Two: DirectX locks in PC game developers. Chapter Three: Xbox uses losses to block Sony. Chapter Four: Sega's act of grace accidentally births NVIDIA. Chapters Five and Six: Linux's counterattack and Steam's new lock-in. Chapter Seven: CUDA's four-layer prison. Chapter Eight: TSMC's trust monopoly. Chapter Nine: Intel's MDF locks in itself. Chapter Ten: Microsoft and Sony dismantle their own pressure-testing grounds."}),"\n",(0,s.jsxs)(t.p,{children:["Eight variations. The locks take different forms, but they share one trait: ",(0,s.jsx)(t.strong,{children:"every lock spread outward."})," DirectX spread from PC gaming to the entire Windows development ecosystem. CUDA spread from gaming GPUs to global AI infrastructure. TSMC's trust monopoly spread from gaming chip fabrication to all fabless clients. These locks penetrated platform boundaries, penetrated generational transitions, penetrated industry walls. Their costs are still being divided today."]}),"\n",(0,s.jsx)(t.p,{children:"In Chapter Eleven, the pattern inverted."}),"\n",(0,s.jsx)(t.p,{children:'Nintendo is not a company that "didn\'t build platform lock-in." Quite the opposite \u2014 in 1985, it embedded the 10NES lock chip in NES cartridges, establishing the first hardware-level gatekeeping mechanism in the history of the gaming industry. A decade before DirectX. Two decades before CUDA. Its licensing regime \u2014 annual quotas, exclusivity periods, exclusive cartridge manufacturing \u2014 was unmatched in its era.'}),"\n",(0,s.jsxs)(t.p,{children:["But Nintendo's lock has one characteristic that sets it apart from every lock described in the preceding ten chapters: ",(0,s.jsx)(t.strong,{children:"It never spread outward."})]}),"\n",(0,s.jsx)(t.p,{children:"The NES's 10NES didn't affect PCs. Didn't affect the Mega Drive. Didn't affect PlayStation. Nintendo never attempted to make its own technology an industry standard, never entered the DirectX vs. Vulkan standards wars, never tried to use its lock to grip the world beyond its platform. Its stance has never wavered: enter my garden, play by my rules. Don't want to come in? I don't care."}),"\n",(0,s.jsx)(t.p,{children:"Sega went to the other extreme. It didn't even build a basic wall. Dreamcast's anti-piracy measures were virtually nonexistent, development barriers were deliberately lowered, the gate stood wide open. Result: when PS2 arrived, Sega died."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Three types of lock. Three outcomes."})}),"\n",(0,s.jsx)(t.p,{children:"Expansive lock-in \u2014 Microsoft, NVIDIA, TSMC, Valve \u2014 became the infrastructure of tech hegemony. Costs borne downstream. Deferred bills arriving two or three decades later."}),"\n",(0,s.jsx)(t.p,{children:"Walled-garden lock-in \u2014 Nintendo \u2014 survived for forty years, but remained irrelevant to the mainline of tech hegemony. A garden, not a supply chain. The NVIDIA Ampere chip inside the Switch shares the same design lineage as the H100. But Nintendo has never cared about AI. It only cares whether a game is fun."}),"\n",(0,s.jsx)(t.p,{children:"No lock \u2014 Sega \u2014 death. Shoichiro Irimajiri's $5 million act of grace is Sega's last fingerprint on the history of technology."}),"\n",(0,s.jsx)(t.p,{children:"Eight expansions. One walled garden. One without walls. Eleven chapters of causal chains, all converging on the same starting point: someone wanted to play a better game."}),"\n",(0,s.jsx)(t.p,{children:"This is the book's final arithmetic."}),"\n",(0,s.jsx)(t.p,{children:"Games are not an industry. Games are a pressure-testing ground \u2014 the most grueling pressure-testing ground on earth. They force GPUs to their limits, force fabrication processes to their limits, force operating systems to their limits, force human engineers to their limits. And in the process of being pushed to those limits, they inadvertently laid the foundational tracks for the AI revolution, smartphones, and the global semiconductor landscape."}),"\n",(0,s.jsx)(t.p,{children:"Games are also a mirror. They reflect the true face of every tech giant \u2014 who treats users as ends, who treats them as means. Microsoft used games to plug a wall, then tore it down when done. Sony used games for the balance sheet, then swapped them out when the format didn't fit. NVIDIA used games to feed CUDA, then pivoted to AI once it was fed. Nintendo built the strictest walls of all, but inside those walls, it treated games as games from beginning to end. Sega didn't build walls at all \u2014 it handed its goodwill to a stranger, and then it died."}),"\n",(0,s.jsxs)(t.p,{children:["The preface asked a question: ",(0,s.jsx)(t.strong,{children:"In the AI era, can we still cultivate the next generation of Carmacks, Lisa Sus, Morris Changs?"})]}),"\n",(0,s.jsx)(t.p,{children:"The answer depends on two things."}),"\n",(0,s.jsx)(t.p,{children:"First: whether anyone is still making the kind of product that forces young people to penetrate the black box \u2014 the kind of thing that keeps you up all night trying to fix a bug or squeeze out ten more frames per second."}),"\n",(0,s.jsx)(t.p,{children:"Second: whether anyone is still protecting that pressure-testing ground \u2014 keeping it from being torn down to build AI data centers, keeping it from being converted into a microtransaction harvesting machine, keeping it from being swallowed by Wall Street's recurring-revenue fixation."}),"\n",(0,s.jsx)(t.p,{children:"If these two things are still happening, the next generation of systems-thinking engineers will have soil. If they vanish \u2014 if the last pressure-testing ground is dismantled, if the last company willing to ship a complete game surrenders to Wall Street \u2014"}),"\n",(0,s.jsx)(t.p,{children:"Then this book is an obituary."}),"\n",(0,s.jsx)(t.p,{children:"If they are still happening \u2014"}),"\n",(0,s.jsx)(t.p,{children:"Then this book is a user's manual. For the next person who, at two in the morning, for the sake of getting a game to run, is willing to open the case and look the silicon in the eye."}),"\n",(0,s.jsx)(t.p,{children:"(End)"}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.img,{src:n(398).A+"",width:"1200",height:"655"})})]})}function c(e={}){const{wrapper:t}={...(0,i.R)(),...e.components};return t?(0,s.jsx)(t,{...e,children:(0,s.jsx)(d,{...e})}):d(e)}},398(e,t,n){n.d(t,{A:()=>s});const s=n.p+"assets/images/ch12_zh 1-054c728879404faf4d87a60cda67153d.png"},8453(e,t,n){n.d(t,{R:()=>r,x:()=>o});var s=n(6540);const i={},a=s.createContext(i);function r(e){const t=s.useContext(a);return s.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function o(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:r(e.components),s.createElement(a.Provider,{value:t},e.children)}}}]);